int dp[105][105][3];
int dfs(int x, int y, int xian, int jian, int yan) {
    if(dp[x][y][yan]>jian){
        dp[x][y][yan]=jian;
	if (x == m && y == m) {
		return jian;
	} else {
		int minn = 1e8;
		if (xian==0) {
			for (int i = 0; i < 4; i++) {
				int mx = x + dx[i];
				int my = y + dy[i];
				if(mx>m||my>m) continue;
				if (yan == a[mx][my]) {
					minn = min(dfs(mx, my, 0, jian, yan), minn);
				} else if (a[mx][my] != 0) {
					minn = min(dfs(mx, my, 0, jian + 1, a[mx][my]), minn);
				} else {
					minn = min(dfs(mx, my, 1, jian + 2+int(yan!=1), 1), minn);
					minn = min(dfs(mx, my, 1, jian + 2+int(yan!=2), 2), minn);
				}
			}
		} else {
			for (int i = 0; i < 4; i++) {
				int mx = x + dx[i];
				int my = y + dy[i];
				if(mx>m||my>m) continue;
				if (yan == a[mx][my]) {
					minn = min(dfs(mx, my, 0, jian, yan), minn);
				} else if (a[mx][my] != 0) {
					minn = min(dfs(mx, my, 0, jian + 1, a[mx][my]), minn);
				}
			}
		}
		return minn;
	}

    }
    return 1e8;
}
